    final bodyBytes = utf8.encode('{"item_id":"c892496f-b1fd-4b91-bdb8-b46f92df1716","name":"Item"}');
    ioReq.contentLength = bodyBytes.length;
    ioReq.add(bodyBytes);
    final ioResp = await ioReq.close();
    final bodyStr = await ioResp.transform(utf8.decoder).join();
    expect(ioResp.statusCode, equals(200), reason: 'status code mismatch');
    final bodyJson = jsonDecode(bodyStr);
    final expectedJson = jsonDecode('{"item_id":"c892496f-b1fd-4b91-bdb8-b46f92df1716","name":"Item"}');
    expect(bodyJson, equals(expectedJson), reason: 'body mismatch');
  })));

